import{c as r,Q as t,j as i,m as o}from"./chunks/framework.BXc4yaFE.js";const p=JSON.parse('{"title":"Cursor: Continually Improving Our Agent Harness","description":"","frontmatter":{"url":"https://cursor.com/blog/continually-improving-agent-harness","date":"2026-05-09T00:00:00.000Z","authors":"Cursor Research Team","source":"Cursor Official Blog","tags":["harness-engineering","Terminal-Bench","model-specific-tools","optimization-loop","Model-Harness-Fit"]},"headers":[],"relativePath":"research/ai-articles/scored/2026-05-09-cursor-continually-improving-agent-harness.md","filePath":"research/ai-articles/scored/2026-05-09-cursor-continually-improving-agent-harness.md","lastUpdated":1779894392000}'),a={name:"research/ai-articles/scored/2026-05-09-cursor-continually-improving-agent-harness.md"};function n(l,e,s,d,c,u){return t(),i("div",null,[...e[0]||(e[0]=[o('<h1 id="cursor-continually-improving-our-agent-harness" tabindex="-1">Cursor: Continually Improving Our Agent Harness <a class="header-anchor" href="#cursor-continually-improving-our-agent-harness" aria-label="Permalink to &quot;Cursor: Continually Improving Our Agent Harness&quot;">​</a></h1><p><strong>原始來源</strong>：<a href="https://cursor.com/blog/continually-improving-agent-harness" target="_blank" rel="noreferrer">https://cursor.com/blog/continually-improving-agent-harness</a><br><strong>作者</strong>：Cursor Research Team<br><strong>歸檔日期</strong>：2026-05-09</p><hr><h2 id="tl-dr" tabindex="-1">TL;DR <a class="header-anchor" href="#tl-dr" aria-label="Permalink to &quot;TL;DR&quot;">​</a></h2><p>Cursor 團隊量化了 harness 對模型效能的影響：相同模型配置不同 harness 可造成數個百分點的差異。核心實踐是「model-specific tool tuning」—OpenAI 模型用 patch-based 編輯、Claude 用 string replacement，並透過 A/B testing + 異常檢測系統化改進。</p><hr><h2 id="核心主張" tabindex="-1">核心主張 <a class="header-anchor" href="#核心主張" aria-label="Permalink to &quot;核心主張&quot;">​</a></h2><ol><li><p><strong>Model-Harness-Fit 量化證據</strong></p><ul><li>「Harness 和模型共同決定 agent 品質」（the harness and the model together determine how good the agent is）</li><li>給模型陌生的工具格式會增加 reasoning tokens 並提升錯誤率</li><li>Cursor 的量化：修改一項 harness 參數可移動整個 benchmark 排名（從 Top 30 跳至 Top 5）</li></ul></li><li><p><strong>Model-Specific Tool Provisioning</strong></p><ul><li>OpenAI 模型被 trained on patch-based diffs（V4A 格式）→ Cursor 給 <code>apply_patch</code> 工具</li><li>Anthropic Claude 被 trained on string replacement → Cursor 給 <code>Edit</code> 工具 + Read</li><li>「Different frontiers trained on different tool shapes」= post-training 的直接結果</li></ul></li><li><p><strong>模型行為差異深於表面風格</strong></p><ul><li>OpenAI 模型：「more literal and precise in instruction following」</li><li>Claude：「more intuitive and more tolerant to imprecise instructions」</li><li>「Context Anxiety」的差異：一個模型因 context 填滿而拒工作，另一個則健壯運行</li><li>Harness 設計必須 account for 這些細微差異</li></ul></li><li><p><strong>Harness Engineering 如同可量測迴圈</strong></p><ul><li>Offline：CursorBench 標準化品質檢測</li><li>Online：A/B testing + Keep Rate 測量（代碼最終留在 codebase 的比率）</li><li>自動異常檢測 + 週報：修復工具呼叫的 reliability 到「2 個 9s 或 3 個 9s」</li></ul></li></ol><hr><h2 id="直接意涵" tabindex="-1">直接意涵 <a class="header-anchor" href="#直接意涵" aria-label="Permalink to &quot;直接意涵&quot;">​</a></h2><h3 id="cc-workspace-可行動性" tabindex="-1">cc-workspace 可行動性 <a class="header-anchor" href="#cc-workspace-可行動性" aria-label="Permalink to &quot;cc-workspace 可行動性&quot;">​</a></h3><ol><li><p><strong>Haiku/Sonnet/Opus 三層模型的 harness 調整需求</strong></p><ul><li>cc-workspace 跨三個 Anthropic 模型（Haiku 4.5, Sonnet 4.6, Opus 4.7）</li><li>推薦在 <code>.claude/refs/model-selection-grid.md</code> 中標記「each model generation may require harness tuning」</li><li>現狀：subagent-strategy.md 選擇模型，但未記錄「選定後需驗證該模型對現有 harness 是否仍最優」</li></ul></li><li><p><strong>Tool Reliability 量化指標</strong></p><ul><li>Cursor 達成「2-3 個 9s of reliability」為基準</li><li>cc-workspace 缺乏對 Read/Write/Edit/Bash/Monitor 這些工具的 error rate 監測</li><li>建議補充進 <code>.claude/rules/output-discipline.md</code> 或新增 <code>.claude/refs/tool-reliability.md</code></li></ul></li><li><p><strong>A/B Testing 文化</strong></p><ul><li>Cursor 的每項 harness 改動都透過 Keep Rate + 語言模型分析驗證</li><li>cc-workspace 當前依賴人工 session feedback，無系統化的 harness 變更前後對比</li><li>適合納入 long-term roadmap（非立即可行，但教科書級實踐）</li></ul></li></ol><hr><h2 id="評分" tabindex="-1">評分 <a class="header-anchor" href="#評分" aria-label="Permalink to &quot;評分&quot;">​</a></h2><table tabindex="0"><thead><tr><th>維度</th><th>分數</th><th>理由</th></tr></thead><tbody><tr><td>A. Workspace 可行動性</td><td>8/10</td><td>具體論述 model-specific tool provisioning，直接影響 Haiku/Sonnet/Opus 選擇決策</td></tr><tr><td>B. 創新性</td><td>7/10</td><td>Model-specific tuning 不新奇，但「3-model reliability framework」體系化程度高</td></tr><tr><td>C. 證據品質</td><td>9/10</td><td>量化 harness impact（Top 30→5 的躍升），A/B test 數據充分</td></tr><tr><td>D. 技術深度</td><td>8/10</td><td>工具差異（patch vs string replace）、模型行為特徵（literal vs intuitive）都有細節</td></tr><tr><td>E. 泛化性</td><td>8/10</td><td>原則適用所有多模型 agent 平台；Cursor 特定的 Keep Rate 指標未必可直接轉移</td></tr><tr><td><strong>加權總分</strong></td><td><strong>8.0/10</strong></td><td>8×0.3 + 7×0.2 + 9×0.2 + 8×0.15 + 8×0.15 = 2.4+1.4+1.8+1.2+1.2 = 8.0</td></tr></tbody></table><p><strong>整合決策</strong>：Rule（補充進 <code>.claude/refs/model-selection-grid.md</code> 的 harness-tuning requirements）</p><hr><h2 id="引用關聯" tabindex="-1">引用關聯 <a class="header-anchor" href="#引用關聯" aria-label="Permalink to &quot;引用關聯&quot;">​</a></h2><ul><li>推文 @nicbstme 2026-05-04：Cursor「Top 30→Top 5 harness-only」</li><li><code>.claude/refs/model-selection-grid.md</code>：模型選擇決策樹</li><li><code>.claude/rules/subagent-strategy.md</code>：三層模型委派規則</li><li>Terminal-Bench 2.0：Harness impact 量化基準</li></ul>',19)])])}const g=r(a,[["render",n]]);export{p as __pageData,g as default};
